async (params, browser) => {
  // Open hotel page with dates
  await browser.open(`${params.hotel_url}?checkin=${params.checkin}&checkout=${params.checkout}`)

  // Wait for hotel page to load
  await browser.waitForSelector('h2.pp-header__title, [data-testid=\'header-title\'], .hp__hotel-name, #hp_hotel_name', 15000)

  // Let page and prices render
  await browser.wait(3000)

  // Scroll to room availability section
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further for all rooms
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract room prices for dates
  const price_comparison = await browser.evaluate(`const nameEl = document.querySelector('h2.pp-header__title, [data-testid="header-title"], .hp__hotel-name, #hp_hotel_name'); const hotelName = nameEl ? nameEl.textContent.trim() : ''; const rooms = []; const roomBlocks = document.querySelectorAll('.hprt-table tr, [data-testid="availability-row"], table.hprt-table tbody tr, .js-rt-block-row'); roomBlocks.forEach(function(el, idx) { if (idx >= 20) return; const roomNameEl = el.querySelector('.hprt-roomtype-icon-link, [data-testid="room-type-link"], a.hprt-roomtype-link, .room_link strong'); const priceEl = el.querySelector('.hprt-price-price, [data-testid="price-and-discounted-price"], .bui-price-display__value, .prco-valign-middle-helper'); const originalPriceEl = el.querySelector('.hprt-price-price-original, .bui-price-display__original, .prco-text-nowrap-helper del'); const occupancyEl = el.querySelector('.hprt-occupancy-occupancy-info, [data-testid="occupancy-popup"], .hprt-occupancy-occupancy-info .invisible_spoken'); const mealEl = el.querySelector('.hprt-mealplan, [data-testid="meal-plan"], .hprt-board-type'); const cancellationEl = el.querySelector('.hprt-conditions, [data-testid="cancellation-policy"], .room-info__cancellation'); const bedEl = el.querySelector('.hprt-roomtype-bed, .hprt-bedcell, [data-testid="bed-type"]'); if (roomNameEl || priceEl) { rooms.push({ room_type: roomNameEl ? roomNameEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', bed_type: bedEl ? bedEl.textContent.trim() : '', occupancy: occupancyEl ? occupancyEl.textContent.trim() : '', meal_plan: mealEl ? mealEl.textContent.trim() : '', cancellation: cancellationEl ? cancellationEl.textContent.trim().substring(0, 200) : '' }); } }); const taxInfoEl = document.querySelector('.hprt-price-tax-rate, [data-testid="taxes-and-charges"], .prd-taxes-and-fees-under-price'); return { hotel_name: hotelName, checkin: params.checkin, checkout: params.checkout, tax_info: taxInfoEl ? taxInfoEl.textContent.trim() : '', room_count: rooms.length, rooms: rooms, url: window.location.href }`)

  return price_comparison
}
